self
            .metadata_manager
            .worker_actor_count()?
            .into_iter()
            .filter_map(|(worker_id, actor_count)| {
                running_worker_parallelism
                    .get(&worker_id)
                    .map(|parallelism| {
                        (
                            worker_id,
                            WorkerActorCount {
                                actor_count,
                                parallelism: *parallelism,
                            },
                        )
                    })
            }).collect

self
            .hummock_manager
            .list_branched_objects()
            .await
